+		exec, ok := c.executor.(*DefaultExecutor)
+		if !ok {
+			t.Fatal("executor should be *DefaultExecutor")
+		}
+		if exec.BinaryPath != "cass" {
+			t.Errorf("BinaryPath = %q, want %q (empty path should be no-op)", exec.BinaryPath, "cass")
