+	t.Run("with custom executor", func(t *testing.T) {
+		t.Parallel()
+		custom := &DefaultExecutor{BinaryPath: "custom-cass"}
+		c := NewClient(WithExecutor(custom))
+		if c.executor != custom {
+			t.Error("executor should be the custom one")
+		}
